    public void handleTrade(Client client, Object message)
    {
        //
        //     {
        //         "e": "aggTrade",
        //         "E": 1754551358681,
        //         "a": 20505890,
        //         "s": "BTCUSDT",
        //         "p": "114783.7",
        //         "q": "0.020",
        //         "f": 26024678,
        //         "l": 26024682,
        //         "T": 1754551358528,
        //         "m": false
        //     }
        //
        Object marketType = this.getAccountTypeFromUrl(client.url);
        Object trade = message;
        Object marketId = this.safeString(trade, "s");
        Object market = this.safeMarket(marketId, null, null, marketType);
        Object parsed = this.parseWsTrade(trade, market);
        Object symbol = Helpers.GetValue(parsed, "symbol");
        if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
        {
            return;
        }
        if (!Helpers.isTrue((Helpers.inOp(this.trades, symbol))))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            Helpers.addElementToObject(this.trades, symbol, new ArrayCache(((Number)limit).intValue()));
        }
        Object stored = Helpers.GetValue(this.trades, symbol);
        Helpers.callDynamically(stored, "append", new Object[]{parsed});
        client.resolve(stored, Helpers.add("trade::", symbol));
    }

    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        // public watchTrades (spot)
        //
        //     {
        //        "e": "aggTrade",  // Event type
        //        "E": 123456789,   // Event time
        //        "s": "BNBBTC",    // Symbol
        //        "a": 12345,       // Aggregate trade ID
        //        "p": "0.001",     // Price
        //        "q": "100",       // Quantity
        //        "f": 100,         // First trade ID
        //        "l": 105,         // Last trade ID
        //        "T": 123456785,   // Trade time
        //        "m": true,        // Is the buyer the market maker?
        //        "M": true         // Ignore
        //     }
        //
        // private watchMyTrades spot
        //
        //     {
        //         "e": "executionReport",
        //         "E": 1611063861489,
        //         "s": "BNBUSDT",
        //         "c": "m4M6AD5MF3b1ERe65l4SPq",
        //         "S": "BUY",
        //         "o": "MARKET",
        //         "f": "GTC",
        //         "q": "2.00000000",
        //         "p": "0.00000000",
        //         "P": "0.00000000",
        //         "F": "0.00000000",
        //         "g": -1,
        //         "C": '',
        //         "x": "TRADE",
        //         "X": "PARTIALLY_FILLED",
        //         "r": "NONE",
        //         "i": 1296882607,
        //         "l": "0.33200000",
        //         "z": "0.33200000",
        //         "L": "46.86600000",
        //         "n": "0.00033200",
        //         "N": "BNB",
        //         "T": 1611063861488,
        //         "t": 109747654,
        //         "I": 2696953381,
        //         "w": false,
        //         "m": false,
        //         "M": true,
        //         "O": 1611063861488,
        //         "Z": "15.55951200",
        //         "Y": "15.55951200",
        //         "Q": "0.00000000"
        //     }
        //
        // private watchMyTrades future/delivery
        //
        //     {
        //         "s": "BTCUSDT",
        //         "c": "pb2jD6ZQHpfzSdUac8VqMK",
        //         "S": "SELL",
        //         "o": "MARKET",
        //         "f": "GTC",
        //         "q": "0.001",
        //         "p": "0",
        //         "ap": "33468.46000",
        //         "sp": "0",
        //         "x": "TRADE",
        //         "X": "FILLED",
        //         "i": 13351197194,
        //         "l": "0.001",
        //         "z": "0.001",
        //         "L": "33468.46",
        //         "n": "0.00027086",
        //         "N": "BNB",
        //         "T": 1612095165362,
        //         "t": 458032604,
        //         "b": "0",
        //         "a": "0",
        //         "m": false,
        //         "R": false,
        //         "wt": "CONTRACT_PRICE",
        //         "ot": "MARKET",
        //         "ps": "BOTH",
        //         "cp": false,
        //         "rp": "0.00335000",
        //         "pP": false,
        //         "si": 0,
        //         "ss": 0
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object e = this.safeString(trade, "e");
        Object isPublicTrade = Helpers.isTrue((Helpers.isEqual(e, "trade"))) || Helpers.isTrue((Helpers.isEqual(e, "aggTrade")));
        Object id = this.safeString2(trade, "t", "a");
        Object timestamp = this.safeInteger(trade, "T");
        Object price = this.safeString2(trade, "L", "p");
        Object amount = null;
        if (Helpers.isTrue(isPublicTrade))
        {
            amount = this.safeString(trade, "q");
        } else
        {
            // private trades, amount is in 'l' field, quantity of the last filled trade
            amount = this.safeString(trade, "l");
        }
        Object cost = this.safeString(trade, "Y");
        if (Helpers.isTrue(Helpers.isEqual(cost, null)))
        {
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(price, null))) && Helpers.isTrue((!Helpers.isEqual(amount, null)))))
            {
                cost = Precise.stringMul(price, amount);
            }
        }
        Object marketId = this.safeString(trade, "s");
        Object defaultType = ((Helpers.isTrue((Helpers.isEqual(market, null))))) ? this.safeString(this.options, "defaultType", "spot") : Helpers.GetValue(market, "type");
        Object symbol = this.safeSymbol(marketId, market, null, defaultType);
        Object side = this.safeStringLower(trade, "S");
        Object takerOrMaker = null;
        Object orderId = this.safeString(trade, "i");
        if (Helpers.isTrue(Helpers.inOp(trade, "m")))
        {
            if (Helpers.isTrue(Helpers.isEqual(side, null)))
            {
                side = ((Helpers.isTrue(Helpers.GetValue(trade, "m")))) ? "sell" : "buy"; // this is reversed intentionally
            }
            takerOrMaker = ((Helpers.isTrue(Helpers.GetValue(trade, "m")))) ? "maker" : "taker";
        }
        Object fee = null;
        Object feeCost = this.safeString(trade, "n");
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "N");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", feeCurrencyCode );
            }};
        }
        Object type = this.safeStringLower(trade, "o");
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalSide = side;
        final Object finalPrice = price;
        final Object finalAmount = amount;
        final Object finalCost = cost;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", AsterCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "id", id );
            put( "order", orderId );
            put( "type", type );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "side", finalSide );
            put( "price", finalPrice );
            put( "amount", finalAmount );
            put( "cost", finalCost );
            put( "fee", finalFee );
        }});
    }

